        v:Dispose()
    end
    self._resRequesterList = {}

    if self._unitMgr then
        self._unitMgr:Dispose()
        self._unitMgr = nil
    end

    if self._treeUpLevelSprite then
        self._treeUpLevelSprite:Dispose()
        self._treeUpLevelSprite = nil
    end


    LDreamTripBase.Dispose(self)
end

