function LDreamTripView:InitDreamTripMap(mapTrans)
    local mapGo = mapTrans.gameObject

    self._mapGo = mapGo
    self._mapRoot = mapTrans:Find('MapRoot').gameObject
    self._npcRoot = mapTrans:Find('NpcRoot').gameObject
    self._effRoot = mapTrans:Find('EffRoot')
    self._staticRoot = mapTrans:Find('StaticRoot')

    local treeRoot = mapTrans:Find('TreeRoot')
    self:CreateTreeRoot(treeRoot)
    self._treeRoot = treeRoot

    self._buildRoot = mapTrans:Find('BuildRoot')

    local GridRootsTrans = mapTrans:Find('GridRoots')
    self._gridRoots = GridRootsTrans.gameObject
    self._gridRootsTrans = GridRootsTrans

    self._heroRoot = mapTrans:Find('HeroRoot/Stand').gameObject

    self._virtualCamMainGo = mapTrans:Find('ControlRoot/VirtualCameraMain').gameObject
    self._virtualCamMain = self._virtualCamMainGo:GetComponent(typeofCinemachineVirtualCamera)
    self._camPosition = self._virtualCamMainGo.transform.position
    self._recordCamPosition = self._camPosition
    ShowObject(self._virtualCamMainGo, true)
    local cameraFollow = self._virtualCamMainGo:GetComponent(typeofFollowObject)
    self._cameraFollow = cameraFollow
    self._cameraFollow.Target = nil
    local UScreen = UnityEngine.Screen

    local screenHalfSize = Vector2(0,0)
    local Lens = self._virtualCamMain.m_Lens
    if Lens.Orthographic then
        local cameraHigh = GameTable.InsConfigRef["cameraHigh"]
        if cameraHigh and cameraHigh > 0 then
            Lens.OrthographicSize = cameraHigh
            self._virtualCamMain.m_Lens = Lens
        end
        screenHalfSize.y = Lens.OrthographicSize
        screenHalfSize.x = screenHalfSize.y * UScreen.width / UScreen.height
    end
    local x = self._rangeX.y * 0.5
    local y = self._rangeY.y * 0.5
    local maxX = x - screenHalfSize.x
    local maxY = y - screenHalfSize.y

    cameraFollow.isLimitBounds = true
    cameraFollow.minLimit = Vector3(-maxX ,-maxY, -9999)
    cameraFollow.maxLimit = Vector3(maxX ,maxY, 9999)

    self._camRangX = Vector2(-maxX,maxX)
    self._camRangY = Vector2(-maxY,maxY)
end

function LDreamTripView:CreateGridRoots()
    local mapEditId = CtrlCenter.DreamTrip:GetMapEditId()
    if not mapEditId then return end
    local mapShowData = require("datal."..mapEditId.."MapData")
    if not mapShowData then return end

    local mapRefId = CtrlCenter.DreamTrip:GetMapRefId()
    if not mapRefId then return end

    self._needPlayAniTrans = {}

    self._needLoadPrefabNum = 0
    self._loadPrefabNum = 0

    local mapInfos = mapShowData.mapInfos or {}

    --local gridStartPrefabPath = mapInfos.gridStartPrefabPath
    --local gridStartPrefabName = mapInfos.gridStartPrefabName
    --
    --local gridNormalPrefabPath = mapInfos.gridNormalPrefabPath
    --local gridNormalPrefabName = mapInfos.gridNormalPrefabName
    --
    --local gridEndPrefabPath = mapInfos.gridEndPrefabPath
    --local gridEndPrefabName = mapInfos.gridEndPrefabName

    local gridTrans = self._gridRootsTrans
    local gridInfos = mapShowData.gridInfos or {}
    local treeInfos = mapShowData.treeInfos or {}
    local buildInfos = mapShowData.buildInfos or {}

    local gridInfoLen = #gridInfos
    local prefabPath,prefabName

    self._needLoadPrefabNum = gridInfoLen + 2 + #buildInfos

    self:LoadPrefab({
        prefabPath = mapInfos.bgLayerPrefabPath,
        prefabName = mapInfos.bgLayerPrefabName,
        name = "bgLayer",
        sortingLayerName = mapInfos.sortingLayerName,
        sortingOrder = mapInfos.sortingOrder,
        pos = Vector3(mapInfos.gridX,mapInfos.gridY,mapInfos.gridZ),
        parentTrans = self._mapRoot.transform,
        scale = Vector3(mapInfos.scaleX,mapInfos.scaleY,mapInfos.scaleZ),
        bShow = true,
        prefabType = PrefabLoadType.BgLayer,
        createCb = function(trans)
            self:CreateEffect(trans,"beijingfenwei_1")
        end
    })


    self:LoadPrefab({
        prefabPath = treeInfos.treePrefabPath,
        prefabName = treeInfos.treePrefabName,
        name = "TreeRoot",
        parentTrans = self._treeRoot.transform,
        scale = Vector3(treeInfos.scaleX,treeInfos.scaleY,treeInfos.scaleZ),
        bShow = true,
        prefabType = PrefabLoadType.Tree,
    })
    self._treeRoot.transform.position = Vector3(treeInfos.gridX,treeInfos.gridY,treeInfos.gridZ)

    local buildZ
    for i,v in ipairs(buildInfos) do
        buildZ = v.gridZ
        --if buildZ > rolePosZ then
        --    buildZ = rolePosZ - i
        --end
        self:LoadPrefab({
            prefabPath = v.buildPrefabPath,
            prefabName = v.buildPrefabName,
            name = "Build-" .. v.refId,
            sortingLayerName = v.sortingLayerName,
            sortingOrder = v.sortingOrder,
            pos = Vector3(v.gridX,v.gridY,buildZ),
            parentTrans = self._buildRoot,
            scale = Vector3(v.scaleX,v.scaleY,v.scaleZ),
            bShow = false,
            prefabType = PrefabLoadType.Build,
        })
    end

    local gridPrefabInfoMap = CtrlCenter.DreamTrip:GetInsPlatformResourceList(mapRefId)
    local prefabInfo
    for i,v in ipairs(gridInfos) do
        prefabInfo = gridPrefabInfoMap[i]
        if prefabInfo then
            prefabPath,prefabName = prefabInfo.path,prefabInfo.prefabName
        else
            --if i == 1 then
            --    prefabPath,prefabName = gridStartPrefabPath,gridStartPrefabName
            --elseif i == gridInfoLen then
            --    prefabPath,prefabName = gridEndPrefabPath,gridEndPrefabName
            --else
            --    prefabPath,prefabName = gridNormalPrefabPath,gridNormalPrefabName
            --end
        end
        self:LoadPrefab({
            prefabPath = prefabPath,
            prefabName = prefabName,
            name = gridTargetName .. i,
            sortingLayerName = v.sortingLayerName,
            sortingOrder = v.sortingOrder,
            pos = Vector3(v.gridX,v.gridY,v.gridZ),
            parentTrans = gridTrans,
            scale = Vector3(v.scaleX,v.scaleY,v.scaleZ),
            bShow = false,
            prefabType = PrefabLoadType.Grid,
        })
    end
end

