function LDreamTripView:LoadPrefab(info)
    local requester = self:LoadMapPrefab(info.prefabPath,info.prefabName,function(obj)
        ShowObject(obj,info.bShow)
        local trans = obj.transform

        if info.prefabType and info.prefabType == PrefabLoadType.Build then
            table.insert(self._needPlayAniTrans,trans)
        end

        trans:SetParent(info.parentTrans)
        if info.pos then
            trans.position = info.pos
        end
        if info.scale then
            trans.localScale = info.scale
        end
        trans.name = info.name
        if info.sortingLayerName and info.sortingLayerName then
            local spriteRender = trans:GetComponent(typeOfSpriteRenderer)
            if spriteRender then
                spriteRender.sortingLayerName = info.sortingLayerName
                spriteRender.sortingOrder = info.sortingOrder
            end
        end

        if info.createCb then
            info.createCb(trans)
        end

        self._loadPrefabNum = self._loadPrefabNum + 1
        if self._loadPrefabNum >= self._needLoadPrefabNum then
            self:LoadGridRoots()
        end
    end)
    if requester ~= nil then
        table.insert(self._resRequesterList, requester)
        requester:StartRequester()
    end
end

---@return LxResRequester
function LDreamTripView:LoadMapPrefab(prefabPath,prefabName, onLoadMap)
    if string.isempty(prefabPath) or string.isempty(prefabName) then
        onLoadMap(nil)
        return
    end
    if LOG_INFO_ENABLED then
        printError("DreamTripView" , "ab name = "..tostring(prefabPath) .." , asset name="..tostring(prefabName))
    end
    local assetPath = "Map/".. prefabPath.."/"..prefabPath..".prefab"
    local requester = LxResUtil.GetAssetRequester(assetPath, typeOfGameObject, function(obj)
        if self._isDisposed then return end
        if obj ~= nil then
            if LOG_INFO_ENABLED then
                printInfo("DreamTripView", "LoadMap::>>"..prefabName.." ok !!!")
            end
            local gameObj = self:CreatePrefabInternal(obj)
            -- callback load
            onLoadMap(gameObj)
        else
            if LOG_INFO_ENABLED then
                printInfo("DreamTripView", "LoadMap::>>"..prefabName.." failed !!!")
            end
        end
    end)
    return requester
end

function LDreamTripView:CreatePrefabInternal(prefab)
    local gameObj = LxResUtil.NewObject(prefab)
    local transform = gameObj.transform
    transform.localScale = Vector3.one
    transform.localPosition = Vector3.zero
    return gameObj
end

