function LDreamTripView:AdjustMapPosition(deltaPosition)
    if self._cameraFollow.Target then
        self._cameraFollow.Target = nil
    end
    self._camPosition.x = self._camPosition.x - deltaPosition.x * 0.01
    self._camPosition.y = self._camPosition.y - deltaPosition.y * 0.01
    self._camPosition.x  = Mathf.Clamp(self._camPosition.x, self._camRangX.x, self._camRangX.y)
    self._camPosition.y  = Mathf.Clamp(self._camPosition.y, self._camRangY.x, self._camRangY.y)
    self._virtualCamMainGo.transform.localPosition = self._camPosition
end

function LDreamTripView:ResetVirtualCamMainGo()
    if not self._cameraFollow.Target and self._unitMgr then
        local playerRoleUnit = self._unitMgr:GetPlayerRoleUnit()
        if playerRoleUnit then
            self._unitMgr:OnUnitViewLoaded(playerRoleUnit)
        end
    end
    self._camPosition = self._recordCamPosition
    self._virtualCamMainGo.transform.localPosition = self._camPosition
end

function LDreamTripView:MakeUnitId()
    local id = self._id + 1
    if id > 2147483647 then
        id = 1
    end
    self._id = id
    return id
end

function LDreamTripView:ShowMainRole(model,pos)
    local unitData = require("LApp.gameplay.dreamTrip.data.LDreamTripUnitData"):new()
    local id = tostring(model)
    unitData.id = id
    unitData.type = CityUnitType.MainRole
    unitData.model = model
    unitData.showType = DreamTripShowType.ShowModel
    pos = pos or Vector3.zero
    pos.z = rolePosZ
    unitData.pos = pos
    unitData.modelScale = Vector3.one
    unitData.gameObjName = "playerObjName"
    self._unitMgr:AddUnitView(unitData)
end

--- 可能涉及动画特效加载
function LDreamTripView:LoadGridRoots()
    if IsNull(self._gridRootsTrans) then return end

    self._gridRootList = {}
    self._gridCXRootList = {}

    local isPlayGridAni = self._playGridAni
    local rootName
    local gridsCount = self._gridsCount
    local gridRootsTrans = self._gridRootsTrans
    for i = 1,gridsCount do
        rootName = gridTargetName .. i
        local trans = gridRootsTrans:Find(rootName)
        local scale = trans.localScale
        if isPlayGridAni then
            trans.localScale = Vector3(0,0,scale.z)
        else
            trans.localScale = Vector3(scale.x,scale.y,scale.z)
        end
        self._gridRootList[i] = trans
        ShowObject(trans.gameObject,true)
        self:CreateCXEff(trans,i)
    end

    if isPlayGridAni then
        self:PlayInitGridAni()
    else
        self:ShowGridInfo()
    end
end

function LDreamTripView:CreateCXEff(gridTrans,index)
    if not self._caixiaEffDpMap then
        self._caixiaEffDpMap = {}
    end

    local effRoot = self._effRoot
    local caixiaEffObj = LxResUtil.NewGameObject("eff_caixia" .. index)
    ShowObject(caixiaEffObj,false)
    caixiaEffObj.layer = effRoot.gameObject.layer
    self._gridCXRootList[index] = caixiaEffObj

    local caixiaEffTrans = caixiaEffObj.transform
    caixiaEffTrans:SetParent(effRoot,false)
    caixiaEffTrans.localScale = Vector3.one
    caixiaEffTrans.localPosition = gridTrans.localPosition
    caixiaEffTrans.localRotation = Quaternion.identity

    self:CreateEffect(caixiaEffTrans,"caigezi_1")
end

function LDreamTripView:CreateEffect(trans,effName)
    local effDp = require("LApp.component.dp.LxEffectDp"):new()
    effDp:SetRendererLayer("Object")
    effDp:InitDp(effName,trans)
    effDp:SetLoadedCallback(function(dp)
    end)
    effDp:Load()
    effDp:SetScale(1)
    effDp:SetLocalPosition(Vector3.zero)
    table.insert(self._caixiaEffDpMap, effDp)
end

function LDreamTripView:PlayInitGridAni()
    if IsNull(self._gridRootsTrans) then return end
    local rootObj = self._gridRootsTrans.gameObject
    local tween = self:NewTweenSeq(rootObj,function()
        self:ShowGridInfo()
    end)
    if self._cameraFollow.Target then
        self._cameraFollow.Target = nil
    end
    local scaleStart = 0.08
    local scaleBig = 0.4
    local scaleSmall = 0.2
    local scaleCenter = 0.1
    local time
    local virtualCamMainTrans = self._virtualCamMainGo.transform
    local camPosition = self._camPosition
    local camPositionZ = camPosition.z
    local moveX,moveY
    local scale,startTime
    for i,gridTrans in ipairs(self._gridRootList) do
        if not IsNull(gridTrans) then
            scale = gridTrans.localScale
            time = scaleStart * i
            startTime = time
            tween:Insert(time,gridTrans:DOScale(Vector3(1.1,1.1,scale.z),scaleBig):SetEase(TweenEase.OutQuad))
            time = time + scaleBig
            tween:Insert(time,gridTrans:DOScale(Vector3(0.9,0.9,scale.z),scaleSmall):SetEase(TweenEase.OutQuad))
            time = time + scaleSmall
            tween:Insert(time,gridTrans:DOScale(Vector3(1,1,scale.z), scaleCenter):SetEase(TweenEase.OutQuad))
            moveX,moveY = self:GetLimitPosition(gridTrans.localPosition)
            tween:Insert(startTime,virtualCamMainTrans:DOLocalMove(Vector3(moveX,moveY,camPositionZ), time - startTime):SetEase(TweenEase.OutQuad))
        end
    end


    local gridRootsLen = #self._gridRootList
    local scaleTreeTime = scaleStart + scaleCenter * gridRootsLen
    local treeRoot = self._treeRoot
    local treeRootPos = treeRoot.localPosition
    local endTime = 0.6
    local buildSize = CtrlCenter.DreamTrip:GetMapBuildSize()
    tween:Insert(scaleTreeTime,treeRoot:DOScale(Vector3(buildSize,buildSize,buildSize), endTime):SetEase(TweenEase.OutQuad))
    tween:Insert(scaleTreeTime,virtualCamMainTrans:DOLocalMove(Vector3(treeRootPos.x,treeRootPos.y,camPositionZ), endTime):SetEase(TweenEase.OutQuad))


    for i,v in ipairs(self._needPlayAniTrans) do
        tween:InsertCallback(scaleTreeTime,function()
            ShowObject(v.gameObject,true)
        end)
    end

    tween:AppendInterval(1)
    tween:PlayForward()
end


function LDreamTripView:GetLimitPosition(targetPos)
    local rangeX = self._camRangX.y
    local rangeY = self._camRangY.y
    local moveX = targetPos.x
    local moveY = targetPos.y
    if math.abs(moveX) > rangeX then
        moveX = moveX >= 0 and rangeX or -rangeX
    end
    if math.abs(moveY) > rangeY then
        moveY = moveY >= 0 and rangeY or -rangeY
    end
    return moveX,moveY
end

function LDreamTripView:ShowGridInfo()
    local playerIndex = CtrlCenter.DreamTrip:GetDreamTripFinalPoint() or 1
    local pos = self:GetGridRootPos(playerIndex)
    self:ShowMainRole(CtrlCenter.DreamTrip:GetMapPlayerShowModel(),pos)

    if self._treeRoot then
        local buildSize = CtrlCenter.DreamTrip:GetMapBuildSize()
        self._treeRoot.localScale = Vector3(buildSize,buildSize,buildSize)
    end

    for i,v in ipairs(self._needPlayAniTrans) do
        ShowObject(v.gameObject,true)
    end

    local mapData = CtrlCenter.DreamTrip:GetDreamTripMapData()
    if mapData then
        self:SetGridRoots(mapData:GetMapDatas())
    end
    self:ShowHeroCXEffShow()
    self:FinishInitMap()
end

