---@param mapDatas table<number,LxInstancePointObj>
function LDreamTripView:SetGridRoots(mapDatas)
    local unitMgr = self._unitMgr
    local resSize,resSite,resSiteX,resSiteY
    local refId,platformRefId,ref
    local heroRefId
    local isBoss

    local modelNum = 1
    local modelInterval = -0.9

    local picNum = 1
    local picInterval = -0.1

    local effectNum = 1
    local effectInterval = -0.1
    local tPosZ
    for i,gridRoot in ipairs(self._gridRootList) do
        local pointObj = mapDatas[i]
        if pointObj then
            refId = pointObj.refId
            --- 地块设置
            ref = GameTable.InsPointRef[refId]
            if ref then
                platformRefId = pointObj.platformRefId
                local showType = ref.showType
                local unitData = require("LApp.gameplay.dreamTrip.data.LDreamTripUnitData"):new()
                unitData.id = self:FindInstanceID(gridRoot)
                unitData.type = DreamTripPlayerType.NPC
                local pos = self:GetRootPos(gridRoot)
                resSiteX,resSiteY = pos.x,pos.y
                if ref.resSite then
                    resSite = ref.resSite
                    if resSite[1] then
                        resSiteX = resSiteX + checknumber(resSite[1])
                    end
                    if resSite[2] then
                        resSiteY = resSiteY + checknumber(resSite[2])
                    end
                end
                local targetName
                local model
                if showType == DreamTripShowType.ShowModel then
                    heroRefId = tonumber(ref.showEntity) or 0
                    local heroEffectRef = GameTable.CharacterEffectRef[heroRefId]
                    if heroEffectRef then
                        model = heroEffectRef.model
                    else
                        if LOG_ERROR_ENABLED then
                            printError("LDreamTripView:","InsPointRef 没有配置 showEntity， refId = %s",refId)
                        end
                        model = "Ailisi"
                    end
                    tPosZ = modelInterval * i
                    modelNum = modelNum + 1
                    targetName = "modelRes"
                elseif showType == DreamTripShowType.ShowPic or showType == DreamTripShowType.ShowTPic then
                    tPosZ = picInterval * i
                    picNum = picNum + 1

                    model = ref.showEntity

                    targetName = showType == DreamTripShowType.ShowPic and "picRes" or "picTweenRes"
                elseif showType == DreamTripShowType.ShowEff then
                    tPosZ = effectInterval * i
                    effectNum = effectNum + 1

                    model = ref.showEntity
                    targetName = "effectRes"
                end
                unitData.gameObjName = string.replace("#a1#-#a2#-#a3#-#a4#",targetName,i,refId,platformRefId)
                pos = Vector3(resSiteX , resSiteY , tPosZ)
                unitData.pos = pos
                unitData.model = model
                unitData.showType = showType
                unitData.index = i
                unitData.pointObj = pointObj
                resSize = ref.resSize
                unitData.modelScale = Vector3(resSize,resSize,resSize)
                isBoss = LxDataHelper.GetInsPlatformRefBossShow(platformRefId)
                ---@type LDreamTripUnitTargetData
                local targetData = nil
                if isBoss then
                    targetData = require("LApp.gameplay.dreamTrip.data.LDreamTripUnitTargetData"):new()
                    local targetType,targetModel,targetPos
                    if showType == DreamTripShowType.ShowModel then
                        targetType = DreamTripShowType.ShowEff
                        targetModel = "tuitu_zhandouzhuangtai"
                        targetPos = Vector3(pos.x,pos.y + 1.7,pos.z)
                    else
                        --targetType = DreamTripShowType.ShowPic
                        --targetModel = "InsSence/ins_icon_boss"
                        targetType = DreamTripShowType.ShowEff
                        targetModel = "tuitu_zhandouzhuangtai"
                        targetPos = Vector3(pos.x,pos.y + 1,pos.z)
                    end
                    targetData.targetType = targetType
                    targetData.targetModel = targetModel
                    targetData.targetPos = targetPos
                end
                unitData.targetData = targetData
                unitMgr:AddUnitView(unitData)
            end
        end
    end
end

function LDreamTripView:FollowTarget(trans, offset)
    if IsNull(self._cameraFollow) then return end
    local targetlocalPos = trans.localPosition
    local moveX,moveY = self:GetLimitPosition(targetlocalPos)
    self._camPosition.x = moveX
    self._camPosition.y = moveY
    local targetPosY = targetlocalPos.y
    if targetPosY ~= moveY then
        offset.y = moveY > targetPosY and moveY - targetPosY or targetPosY - moveY
    end
    self._cameraFollow:SetFollow(trans, offset)
    self._virtualCamMainGo.transform.localPosition = self._camPosition
end

function LDreamTripView:GetGridRoot(index)
    return self._gridRootList[index]
end

function LDreamTripView:PlayPassGridRootAni(index,time,isEmpty,runPosInfo)
    local gridRoot = self:GetGridRoot(index)
    if not gridRoot then return end

    local cxRootObj = self._gridCXRootList[index]
    local obj = gridRoot.gameObject
    local tween = self:NewTweenSeq(obj,function()
        if cxRootObj then
            ShowObject(cxRootObj,false)
        end
        self:SetUnitViewModelDpShow(index,not isEmpty)
        if isEmpty then
            self:ShowHeroCXEffShow()
            self._camPosition = self._virtualCamMainGo.transform.localPosition
        end
    end)
    local smallTime = time / 2
    local scale = gridRoot.localScale
    tween:AppendInterval(0.1)
    tween:AppendCallback(function()
        if cxRootObj then
            ShowObject(cxRootObj,true)
        end
    end)
    tween:Append(gridRoot:DOScale(Vector3(0.7,0.7,scale.z), smallTime):SetEase(TweenEase.OutQuad))
    if runPosInfo and runPosInfo.moveState == DreamTripMoveType.MoveEnd then
        tween:AppendCallback(function()
            local portalIndex = CtrlCenter.DreamTrip:GetPortalTypeGridIndex()
            if portalIndex then
                local unitView = self:GetUnitViewByIndex(portalIndex)
                if unitView then
                    unitView:ShowOnlyOneGameObj()
                end
            end
        end)
    end
    tween:Append(gridRoot:DOScale(Vector3(scale.x,scale.y,scale.z), smallTime):SetEase(TweenEase.OutQuad))
    tween:PlayForward()
end

function LDreamTripView:GetGridRootPos(index)
    local root = self:GetGridRoot(index)
