    local curIdx = CtrlCenter.DreamTrip:GetDreamTripFinalPoint()
    if not curIdx then return end
    for idx,gridCXRootObj in pairs(self._gridCXRootList) do
        ShowObject(gridCXRootObj,curIdx == idx)
    end
end

function LDreamTripView:SetGridCXRootShow(index)
    local gridCXRootObj = self._gridCXRootList[index]
    if IsNull(gridCXRootObj) then return end

    local curIdx = CtrlCenter.DreamTrip:GetDreamTripFinalPoint()
    ShowObject(gridCXRootObj,curIdx == index)
