function LDreamTripView:DoCameraMove(path,func)
    if self._isDisposed then return end

    if IsNull(self._virtualCamMainGo) then return end

    local dreamTripAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.DreamTrip)
    local mapTrans = dreamTripAdapter:GetMapTrans()
    if IsNull(mapTrans) then return end

    local root = mapTrans:Find(path)
    if not root or IsNull(root) then return end

    if self._cameraFollow.Target then
        self._cameraFollow.Target = nil
    end

    local newPos = root.localPosition

    local virtualCamMainGo = self._virtualCamMainGo
    local virtualCamMainTrans = virtualCamMainGo.transform

    local tween = self:NewTweenSeq(virtualCamMainGo,function()
        self._camPosition = self._virtualCamMainGo.transform.localPosition
        if func then func() end
    end)
    local virtualCamMainPos = virtualCamMainTrans.localPosition
    tween:Append(virtualCamMainTrans:DOLocalMove(Vector3(newPos.x,newPos.y,virtualCamMainPos.z),1):SetEase(TweenEase.OutQuad))
    tween:PlayForward()
end

----------------------------------------------------------
---tween
function LDreamTripView:ClearTweenSeq()
    for key, tweenSeq in pairs(self._ui_tweenSeqs) do
        local tween = tweenSeq.tween
        if tween and tween.active then
            tween:Kill(false)
        end
        tweenSeq.tween = nil
        tweenSeq.tarObj = nil
    end
    self._ui_tweenSeqs = {}
end

---@param go GameObject
---@param endAction function
---@param bAutoRelease boolean @ default false
---@return DG.Tweening.Sequence
function LDreamTripView:NewTweenSeq(go, endAction, bAutoRelease)
    if IsNull(go) then return nil end

    local obj = go
    local tween = DOTween.Sequence()
    local key = self:FindInstanceID(obj)
    self._ui_tweenSeqs[key] = { tween = tween, tarObj = obj, autoRelease = bAutoRelease }
    tween:OnComplete(function()
        self:RemoveTweenSeqByKey(key)
        if endAction ~= nil then endAction(obj) end
    end)
    return tween
end

function LDreamTripView:RemoveTweenSeqByKey(key)
    local tweenData = self._ui_tweenSeqs[key]
    if not tweenData then return end

    local tween = tweenData.tween
    local tarObj = tweenData.tarObj
    if tween and tween.active then
        tween:Kill(false)
    end
    if tweenData.autoRelease then
        self._base_instanceIDMap[tarObj] = nil
        LxResUtil.DestroyObject(tarObj)
    end
    tweenData.tween = nil
    tweenData.tarObj = nil
    self._ui_tweenSeqs[key] = nil
end

function LDreamTripView:IsExistTweenSeq(go)
    if IsNull(go) then return nil end

    local key = self:FindInstanceID(go)
    if self._ui_tweenSeqs and self._ui_tweenSeqs[key] then
        return true
    end
    return false
end

function LDreamTripView:GetTweenSeq(go)
    if IsNull(go) then return nil end
    local key = self:FindInstanceID(go)
    if self._ui_tweenSeqs and self._ui_tweenSeqs[key] then
        return self._ui_tweenSeqs[key].tween
    end
end

return LDreamTripView